-- ============================================================
-- FieldTrack 2.0 — Complete Production Schema Baseline
-- ============================================================
-- This file represents the ENTIRE live Supabase database schema
-- as of Phase 28 (2026-03-25).
--
-- Generated by diffing the live Supabase project nvezwhasasykwnnblokk
-- against the Phase 27b document. All divergences resolved.
--
-- This migration can be run on a blank Supabase project to
-- recreate the exact schema without any data.
--
-- Ordering:
-- 1. Extensions
-- 2. Enums
-- 3. Sequences
-- 4. Tables (no FKs)
-- 5. Indexes
-- 6. Functions
-- 7. Triggers
-- 8. RLS Policies
-- 9. Cron Jobs
-- ============================================================

-- ══════════════════════════════════════════════════════════════
-- EXTENSIONS
-- ══════════════════════════════════════════════════════════════

CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE EXTENSION IF NOT EXISTS "pg_cron";
CREATE EXTENSION IF NOT EXISTS "pg_stat_statements";

-- ══════════════════════════════════════════════════════════════
-- ENUMS
-- ══════════════════════════════════════════════════════════════

CREATE TYPE IF NOT EXISTS public.user_role AS ENUM ('ADMIN', 'EMPLOYEE');
CREATE TYPE IF NOT EXISTS public.expense_status AS ENUM ('PENDING', 'APPROVED', 'REJECTED');
CREATE TYPE IF NOT EXISTS public.distance_job_status AS ENUM ('pending', 'processing', 'done', 'failed');

-- ══════════════════════════════════════════════════════════════
-- SEQUENCES
-- ══════════════════════════════════════════════════════════════

CREATE SEQUENCE IF NOT EXISTS public.employee_code_seq
  START WITH 1 INCREMENT BY 1 NO CYCLE;

-- ══════════════════════════════════════════════════════════════
-- TABLES (Core)
-- ══════════════════════════════════════════════════════════════

CREATE TABLE IF NOT EXISTS public.organizations (
  id         UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  name       TEXT        NOT NULL,
  slug       TEXT        UNIQUE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE public.organizations IS
  'Top-level tenant. All other tables scope to organization_id.';

CREATE TABLE IF NOT EXISTS public.users (
  id              UUID             PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID             NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  email           TEXT             NOT NULL UNIQUE,
  role            public.user_role NOT NULL,
  created_at      TIMESTAMPTZ      NOT NULL DEFAULT now(),
  updated_at      TIMESTAMPTZ      NOT NULL DEFAULT now()
);

COMMENT ON TABLE public.users IS
  'Application user profiles linked to auth.users via shared UUID and email.';

CREATE TABLE IF NOT EXISTS public.employees (
  id               UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id  UUID        NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  user_id          UUID        UNIQUE REFERENCES public.users(id) ON DELETE SET NULL,
  name             TEXT        NOT NULL,
  phone            TEXT,
  is_active        BOOLEAN     NOT NULL DEFAULT true,
  created_at       TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at       TIMESTAMPTZ NOT NULL DEFAULT now(),
  -- NOTE: column order matches live DB (employee_code and last_activity_at were added later)
  employee_code    TEXT        NOT NULL UNIQUE,
  last_activity_at TIMESTAMPTZ
);

COMMENT ON TABLE public.employees IS
  'Field employees. One row per employee across organization.';
COMMENT ON COLUMN public.employees.employee_code IS
  'Human-readable identifier e.g. EMP0001. Generated by sequence.';
COMMENT ON COLUMN public.employees.last_activity_at IS
  'Updated on check-in / check-out. Used to compute ACTIVE / RECENT / INACTIVE status.';

CREATE TABLE IF NOT EXISTS public.attendance_sessions (
  id                            UUID                       PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id               UUID                       NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  employee_id                   UUID                       NOT NULL REFERENCES public.employees(id) ON DELETE CASCADE,
  checkin_at                    TIMESTAMPTZ                NOT NULL DEFAULT now(),
  checkout_at                   TIMESTAMPTZ,
  distance_recalculation_status public.distance_job_status NOT NULL DEFAULT 'pending',
  total_distance_km             FLOAT8,
  total_duration_seconds        INT,
  created_at                    TIMESTAMPTZ                NOT NULL DEFAULT now(),
  updated_at                    TIMESTAMPTZ                NOT NULL DEFAULT now()
);

COMMENT ON TABLE public.attendance_sessions IS
  'One row per field session (check-in to check-out). Source for GPS trails and distance jobs.';

CREATE TABLE IF NOT EXISTS public.gps_locations (
  id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID        NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  session_id      UUID        NOT NULL REFERENCES public.attendance_sessions(id) ON DELETE CASCADE,
  employee_id     UUID        NOT NULL REFERENCES public.employees(id) ON DELETE CASCADE,
  latitude        FLOAT8      NOT NULL CHECK (latitude  >= -90  AND latitude  <= 90),
  longitude       FLOAT8      NOT NULL CHECK (longitude >= -180 AND longitude <= 180),
  accuracy        FLOAT8,
  recorded_at     TIMESTAMPTZ NOT NULL,
  sequence_number INT,
  is_duplicate    BOOLEAN     NOT NULL DEFAULT false,
  UNIQUE (session_id, recorded_at)
);

COMMENT ON TABLE public.gps_locations IS
  'Raw GPS breadcrumb trail per session. Duplicate flag set by distance calculation job.
   Phase 27b: Added sequence_number field for monotonic ordering validation.';

CREATE TABLE IF NOT EXISTS public.expenses (
  id                UUID                  PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id   UUID                  NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  employee_id       UUID                  NOT NULL REFERENCES public.employees(id) ON DELETE CASCADE,
  amount            NUMERIC               NOT NULL CHECK (amount > 0),
  description       TEXT                  NOT NULL,
  status            public.expense_status NOT NULL DEFAULT 'PENDING',
  receipt_url       TEXT,
  submitted_at      TIMESTAMPTZ           NOT NULL DEFAULT now(),
  reviewed_at       TIMESTAMPTZ,
  reviewed_by       UUID                  REFERENCES public.users(id) ON DELETE SET NULL,
  created_at        TIMESTAMPTZ           NOT NULL DEFAULT now(),
  updated_at        TIMESTAMPTZ           NOT NULL DEFAULT now(),
  rejection_comment TEXT
);

COMMENT ON TABLE public.expenses IS
  'Employee expense reports with approval workflow.
   Phase 27b: Added rejection_comment field for admin feedback.';

CREATE TABLE IF NOT EXISTS public.session_summaries (
  id                     UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id        UUID        NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  session_id             UUID        NOT NULL UNIQUE REFERENCES public.attendance_sessions(id) ON DELETE CASCADE,
  total_distance_km      FLOAT8      NOT NULL DEFAULT 0,
  total_duration_seconds INT         NOT NULL DEFAULT 0,
  avg_speed_kmh          FLOAT8      NOT NULL DEFAULT 0,
  computed_at            TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_at             TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at             TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE public.session_summaries IS
  'Computed distance/duration/speed per session. Written by BullMQ distance recalculation job.';

CREATE TABLE IF NOT EXISTS public.admin_sessions (
  id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  admin_id        UUID        NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  organization_id UUID        NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  started_at      TIMESTAMPTZ NOT NULL,
  ended_at        TIMESTAMPTZ,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE public.admin_sessions IS
  'Tracks when an admin started/stopped monitoring employees. Audit and compliance trail.';

CREATE TABLE IF NOT EXISTS public.employee_daily_metrics (
  id               UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id  UUID        NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  employee_id      UUID        NOT NULL REFERENCES public.employees(id) ON DELETE CASCADE,
  date             DATE        NOT NULL,
  sessions         INT         NOT NULL DEFAULT 0,
  distance_km      FLOAT8      NOT NULL DEFAULT 0,
  duration_seconds INT         NOT NULL DEFAULT 0,
  expenses_count   INT         NOT NULL DEFAULT 0,
  expenses_amount  NUMERIC     NOT NULL DEFAULT 0,
  created_at       TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at       TIMESTAMPTZ NOT NULL DEFAULT now(),
  CONSTRAINT uq_employee_daily_metrics UNIQUE (employee_id, date)
);

COMMENT ON TABLE public.employee_daily_metrics IS
  'Pre-aggregated daily metrics per employee. Powers leaderboards and analytics dashboards.
   Upserted by API on checkout and expense submission.';

CREATE TABLE IF NOT EXISTS public.org_daily_metrics (
  id                     UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id        UUID        NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  date                   DATE        NOT NULL,
  total_sessions         INT         NOT NULL DEFAULT 0,
  total_distance_km      FLOAT8      NOT NULL DEFAULT 0,
  total_duration_seconds INT         NOT NULL DEFAULT 0,
  active_employees       INT         NOT NULL DEFAULT 0,
  created_at             TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at             TIMESTAMPTZ NOT NULL DEFAULT now(),
  CONSTRAINT uq_org_daily_metrics UNIQUE (organization_id, date)
);

COMMENT ON TABLE public.org_daily_metrics IS
  'Pre-aggregated daily metrics per organization. Powers org-level trend charts.
   Rolled up from employee_daily_metrics by API.';

CREATE TABLE IF NOT EXISTS public.employee_latest_sessions (
  employee_id            UUID        PRIMARY KEY REFERENCES public.employees(id) ON DELETE CASCADE,
  organization_id        UUID        NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  session_id             UUID        REFERENCES public.attendance_sessions(id) ON DELETE SET NULL,
  latest_checkin         TIMESTAMPTZ,
  latest_checkout        TIMESTAMPTZ,
  total_distance_km      FLOAT8,
  total_duration_seconds INT,
  status                 TEXT        CHECK (status IN ('ACTIVE', 'RECENT', 'INACTIVE')),
  updated_at             TIMESTAMPTZ DEFAULT now()
);

COMMENT ON TABLE public.employee_latest_sessions IS
  'Snapshot of each employee''s latest session state. Source of truth for dashboard reads.
   NEVER scan attendance_sessions for dashboard queries — read from here instead.
   Status lifecycle: ACTIVE (trigger) → RECENT (trigger) → INACTIVE (pg_cron hourly).';

-- ══════════════════════════════════════════════════════════════
-- TABLES (Webhooks)
-- ══════════════════════════════════════════════════════════════

CREATE TABLE IF NOT EXISTS public.webhooks (
  id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID        NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  url             TEXT        NOT NULL,
  secret          TEXT        NOT NULL,
  events          TEXT[]      NOT NULL DEFAULT '{}',
  is_active       BOOLEAN     NOT NULL DEFAULT true,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT now()
  -- NOTE: no updated_at in live DB — webhooks are replaced, not updated
);

COMMENT ON TABLE public.webhooks IS
  'Webhook configuration per organization.
   Events: Array of strings (e.g., INVOICE_GENERATED, REPORT_READY).
   secret: used for HMAC-SHA256 signature verification.
   ⚠️  secret is stored in plain text. Future improvement: move to Supabase Vault
   (vault.create_secret) or store only a bcrypt hash, never the raw value.';

-- ── webhook_deliveries ──────────────────────────────────────
-- Live schema is significantly richer than the Phase 25 doc.
-- Key changes vs doc:
--   + organization_id (for RLS scoping)
--   + event_id UUID (idempotency key — unique per event+webhook)
--   + status TEXT with 'pending' default (replaces status_code INT)
--   + response_status INT / response_body TEXT / last_error TEXT
--     (replace status_code INT / response TEXT / error TEXT)
--   + delivered_at TIMESTAMPTZ (replaces updated_at)
--   - updated_at removed
--   - max_retries removed (retry logic now in BullMQ)
CREATE TABLE IF NOT EXISTS public.webhook_deliveries (
  id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  webhook_id      UUID        NOT NULL REFERENCES public.webhooks(id) ON DELETE CASCADE,
  organization_id UUID        NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  event_id        UUID        NOT NULL,
  event_type      TEXT        NOT NULL,
  payload         JSONB       NOT NULL,
  status          TEXT        NOT NULL DEFAULT 'pending',
  attempts        INT         NOT NULL DEFAULT 0,
  response_status INT,
  response_body   TEXT,
  last_error      TEXT,
  next_retry_at   TIMESTAMPTZ,
  delivered_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_at      TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (event_id, webhook_id)
);

COMMENT ON TABLE public.webhook_deliveries IS
  'Webhook delivery attempts and status tracking.
   status: pending | delivered | failed
   event_id: idempotency key — one delivery record per (event, webhook) pair.
   Retry logic handled by BullMQ worker (exponential backoff).';

-- ══════════════════════════════════════════════════════════════
-- TABLES (Queue & Dashboard)
-- ══════════════════════════════════════════════════════════════

-- ── queue_retry_intents ──────────────────────────────────────
-- Live schema differs from Phase 21 doc:
--   + job_key TEXT (replaces job_id TEXT)
--   + payload JSONB (new — stores job data for re-enqueue)
--   + status TEXT with 'pending' default (new)
--   - job_id removed
--   - max_retries removed
--   Unique constraint: (queue_name, job_key)
CREATE TABLE IF NOT EXISTS public.queue_retry_intents (
  id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  queue_name    TEXT        NOT NULL,
  job_key       TEXT        NOT NULL,
  payload       JSONB       NOT NULL,
  status        TEXT        NOT NULL DEFAULT 'pending',
  retry_count   INT         NOT NULL DEFAULT 0,
  next_retry_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  error_message TEXT,
  created_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (queue_name, job_key)
);

COMMENT ON TABLE public.queue_retry_intents IS
  'BullMQ job retry tracking per queue.
   job_key: stable deduplication key per logical job (e.g., session UUID).
   payload: stored for re-enqueue without recomputing.
   status: pending | retrying | exhausted | succeeded';

-- ── org_dashboard_snapshot ───────────────────────────────────
-- Live schema is significantly richer than the Phase 24 doc.
-- Key changes vs doc:
--   - id UUID column removed — organization_id IS the PK
--   - total_employees, active_today, total_distance_today, total_expenses_today removed
--   + active_employee_count, recent_employee_count, inactive_employee_count (status breakdown)
--   + active_employees_today, today_session_count, today_distance_km
--   + pending_expense_count, pending_expense_amount
--   - snapshot_updated_at, created_at removed; only updated_at remains
CREATE TABLE IF NOT EXISTS public.org_dashboard_snapshot (
  organization_id        UUID    PRIMARY KEY REFERENCES public.organizations(id) ON DELETE CASCADE,
  active_employee_count  INT     NOT NULL DEFAULT 0,
  recent_employee_count  INT     NOT NULL DEFAULT 0,
  inactive_employee_count INT    NOT NULL DEFAULT 0,
  active_employees_today INT     NOT NULL DEFAULT 0,
  today_session_count    INT     NOT NULL DEFAULT 0,
  today_distance_km      FLOAT8  NOT NULL DEFAULT 0,
  pending_expense_count  INT     NOT NULL DEFAULT 0,
  pending_expense_amount NUMERIC NOT NULL DEFAULT 0,
  updated_at             TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE public.org_dashboard_snapshot IS
  'Cached dashboard metrics for org home screen.
   organization_id is the PK — one row per org.
   Updated incrementally by API on checkout / expense events.
   Columns reflect the richer Phase 28 dashboard design.';

