-- ── custom_access_token_hook ─────────────────────────────────
CREATE OR REPLACE FUNCTION public.custom_access_token_hook(event jsonb)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_role        public.user_role;
  v_employee_id UUID;
  v_org_id      UUID;
BEGIN
  SELECT role, id, organization_id INTO v_role, v_employee_id, v_org_id
  FROM public.users
  WHERE id = (event->>'sub')::uuid
  LIMIT 1;

  IF v_role IS NULL THEN
    RETURN event;
  END IF;

  event := jsonb_set(event, '{claims,role}',   to_jsonb(v_role::text));
  event := jsonb_set(event, '{claims,org_id}', to_jsonb(v_org_id));

  IF v_role = 'EMPLOYEE' THEN
    SELECT id INTO v_employee_id
    FROM public.employees
    WHERE user_id = (event->>'sub')::uuid
    LIMIT 1;

    IF v_employee_id IS NOT NULL THEN
      event := jsonb_set(event, '{claims,employee_id}', to_jsonb(v_employee_id));
    END IF;
  END IF;

  RETURN event;
END;
$$;

COMMENT ON FUNCTION public.custom_access_token_hook(JSONB) IS
  'Supabase Auth hook to inject custom claims (role, org_id, employee_id) into JWT.';

