-- ROW LEVEL SECURITY
-- ══════════════════════════════════════════════════════════════

ALTER TABLE public.organizations           ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.users                   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.employees               ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.attendance_sessions     ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.gps_locations           ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.expenses                ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.session_summaries       ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.admin_sessions          ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.employee_daily_metrics  ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.org_daily_metrics       ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.employee_latest_sessions ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.webhooks                ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.webhook_deliveries      ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.queue_retry_intents     ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.org_dashboard_snapshot  ENABLE ROW LEVEL SECURITY;

-- ── RLS design notes ──────────────────────────────────────────
--
-- Pattern A — simple org isolation (single subquery):
--   USING (organization_id = (SELECT organization_id FROM public.users WHERE id = auth.uid()))
--
-- Pattern B — role-aware admin policies (single subquery, both fields):
--   Each admin policy does ONE lookup into public.users to get both
--   organization_id AND role simultaneously, avoiding duplicate subqueries.
--   Postgres caches correlated subqueries per row so this is planner-friendly.
--
-- Pattern C — employee self-access (single subquery into employees):
--   USING (employee_id = (SELECT id FROM public.employees WHERE user_id = auth.uid()))
--
-- auth.uid() is called directly — no (SELECT auth.uid()) wrapper needed.
-- The wrapper was a historic Supabase workaround; auth.uid() is now inlined
-- as a stable function and handled correctly by the planner.

-- ── Org isolation policies ─────────────────────────────────────

CREATE POLICY "org_isolation_organizations"
  ON public.organizations FOR ALL
  USING (id = (SELECT organization_id FROM public.users WHERE id = auth.uid()));

CREATE POLICY "org_isolation_users"
  ON public.users FOR ALL
  USING (organization_id = (SELECT organization_id FROM public.users WHERE id = auth.uid()));

CREATE POLICY "org_isolation_admin_sessions"
  ON public.admin_sessions FOR ALL
  USING (organization_id = (SELECT organization_id FROM public.users WHERE id = auth.uid()));

CREATE POLICY "org_isolation_org_daily_metrics"
  ON public.org_daily_metrics FOR ALL
  USING (organization_id = (SELECT organization_id FROM public.users WHERE id = auth.uid()));

CREATE POLICY "org_isolation_webhooks"
  ON public.webhooks FOR ALL
  USING (organization_id = (SELECT organization_id FROM public.users WHERE id = auth.uid()));

-- queue_retry_intents: service_role only — BullMQ worker accesses via service_role key.
-- TO service_role means authenticated users get zero rows (RLS still enabled).
CREATE POLICY "service_role_only_queue_retry_intents"
  ON public.queue_retry_intents
  TO service_role
  USING (true)
  WITH CHECK (true);

-- webhook_deliveries: service_role only — written/read by the webhook worker, never by clients.
CREATE POLICY "org_isolation_webhook_deliveries"
  ON public.webhook_deliveries
  TO service_role
  USING (true)
  WITH CHECK (true);

CREATE POLICY "org_isolation_org_dashboard_snapshot"
  ON public.org_dashboard_snapshot FOR ALL
  USING (organization_id = (SELECT organization_id FROM public.users WHERE id = auth.uid()));

-- ── Phase 27a: Role-aware RLS (split admin_all + employee_self) ─
--
-- Admin policies: single subquery per policy fetches org_id + role together.
-- Employee policies: single subquery into employees for their own id.

-- EXPENSES
CREATE POLICY "expenses_admin_all" ON public.expenses
  FOR ALL TO authenticated
  USING (
    (SELECT organization_id = expenses.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  )
  WITH CHECK (
    (SELECT organization_id = expenses.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  );

CREATE POLICY "expenses_employee_self" ON public.expenses
  FOR ALL TO authenticated
  USING (employee_id    = (SELECT id FROM public.employees WHERE user_id = auth.uid()))
  WITH CHECK (employee_id = (SELECT id FROM public.employees WHERE user_id = auth.uid()));

-- ATTENDANCE_SESSIONS
CREATE POLICY "attendance_sessions_admin_all" ON public.attendance_sessions
  FOR ALL TO authenticated
  USING (
    (SELECT organization_id = attendance_sessions.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  )
  WITH CHECK (
    (SELECT organization_id = attendance_sessions.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  );

CREATE POLICY "attendance_sessions_employee_self" ON public.attendance_sessions
  FOR ALL TO authenticated
  USING (employee_id    = (SELECT id FROM public.employees WHERE user_id = auth.uid()))
  WITH CHECK (employee_id = (SELECT id FROM public.employees WHERE user_id = auth.uid()));

-- GPS_LOCATIONS
CREATE POLICY "gps_locations_admin_all" ON public.gps_locations
  FOR ALL TO authenticated
  USING (
    (SELECT organization_id = gps_locations.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  )
  WITH CHECK (
    (SELECT organization_id = gps_locations.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  );

CREATE POLICY "gps_locations_employee_self" ON public.gps_locations
  FOR ALL TO authenticated
  USING (employee_id    = (SELECT id FROM public.employees WHERE user_id = auth.uid()))
  WITH CHECK (employee_id = (SELECT id FROM public.employees WHERE user_id = auth.uid()));

-- EMPLOYEE_DAILY_METRICS
CREATE POLICY "employee_daily_metrics_admin_all" ON public.employee_daily_metrics
  FOR ALL TO authenticated
  USING (
    (SELECT organization_id = employee_daily_metrics.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  )
  WITH CHECK (
    (SELECT organization_id = employee_daily_metrics.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  );

CREATE POLICY "employee_daily_metrics_employee_self" ON public.employee_daily_metrics
  FOR ALL TO authenticated
  USING (employee_id    = (SELECT id FROM public.employees WHERE user_id = auth.uid()))
  WITH CHECK (employee_id = (SELECT id FROM public.employees WHERE user_id = auth.uid()));

-- SESSION_SUMMARIES
CREATE POLICY "session_summaries_admin_all" ON public.session_summaries
  FOR ALL TO authenticated
  USING (
    (SELECT organization_id = session_summaries.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  )
  WITH CHECK (
    (SELECT organization_id = session_summaries.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  );

CREATE POLICY "session_summaries_employee_self" ON public.session_summaries
  FOR SELECT TO authenticated
  USING (
    session_id IN (
      SELECT id FROM public.attendance_sessions
      WHERE employee_id = (SELECT id FROM public.employees WHERE user_id = auth.uid())
    )
  );

-- EMPLOYEES
CREATE POLICY "employees_admin_all" ON public.employees
  FOR ALL TO authenticated
  USING (
    (SELECT organization_id = employees.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  )
  WITH CHECK (
    (SELECT organization_id = employees.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  );

CREATE POLICY "employees_employee_self" ON public.employees
  FOR SELECT TO authenticated
  USING (user_id = auth.uid());

-- EMPLOYEE_LATEST_SESSIONS
CREATE POLICY "els_admin_all" ON public.employee_latest_sessions
  FOR ALL TO authenticated
  USING (
    (SELECT organization_id = employee_latest_sessions.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  )
  WITH CHECK (
    (SELECT organization_id = employee_latest_sessions.organization_id AND role = 'ADMIN'
     FROM public.users WHERE id = auth.uid())
  );

CREATE POLICY "els_employee_self" ON public.employee_latest_sessions
  FOR SELECT TO authenticated
  USING (employee_id = (SELECT id FROM public.employees WHERE user_id = auth.uid()));

-- ══════════════════════════════════════════════════════════════
-- GRANTS
-- ══════════════════════════════════════════════════════════════

-- Allow authenticated users to call all public RPC functions.
-- Without this, PostgREST RPC calls (e.g. get_org_latest_sessions,
-- get_active_map_markers) fail silently with 404 or permission denied.
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA public TO authenticated;

-- ══════════════════════════════════════════════════════════════
-- CRON JOBS
-- ══════════════════════════════════════════════════════════════

DO $outer$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM cron.job WHERE jobname = 'employee-status-refresh'
  ) THEN
    PERFORM cron.schedule(
      'employee-status-refresh',
      '0 * * * *',
      $cron$
        UPDATE public.employee_latest_sessions
        SET
          status     = 'INACTIVE',
          updated_at = now()
        WHERE status          = 'RECENT'
          AND latest_checkout < now() - interval '24 hours';
      $cron$
    );
  END IF;
END;
$outer$;

-- ══════════════════════════════════════════════════════════════
-- SCHEMA COMPLETE
-- ══════════════════════════════════════════════════════════════
-- Baseline schema migration for FieldTrack 2.0 (Phase 28 / 2026-03-25)
-- Ground-truthed against live Supabase project nvezwhasasykwnnblokk
--
-- Tables:             15 core
-- Enums:              3
-- Sequences:          1
-- Indexes:            ~60 (including partial, unique, GIN, covering)
-- Functions:          11
-- Triggers:           9
-- RLS Policies:       22 across 15 tables
-- Grants:             1 (authenticated → all public functions)
-- Extensions:         4 (uuid-ossp, pgcrypto, pg_cron, pg_stat_statements)
-- Cron Jobs:          1 (employee-status-refresh)
--
-- ── Changes vs Phase 27b document ─────────────────────────────
--
-- queue_retry_intents:
--   BREAKING — job_id + max_retries removed; job_key + payload + status added
--   Unique constraint: (queue_name, job_id) → (queue_name, job_key)
--
-- webhook_deliveries:
--   BREAKING — status_code / response / error replaced by
--   status TEXT / response_status INT / response_body TEXT / last_error TEXT
--   Added: organization_id, event_id (idempotency), delivered_at
--   Removed: updated_at
--   Unique constraint added: (event_id, webhook_id)
--
-- webhooks:
--   updated_at removed; column order adjusted (secret before events)
--
-- org_dashboard_snapshot:
--   BREAKING — id UUID removed; organization_id is now the PK
--   All columns redesigned: status counts, today metrics, pending expenses
--
-- employees:
--   Column order cosmetically different (employee_code + last_activity_at
--   were added via ALTER in earlier migrations)
--
-- Indexes (live DB extras vs doc):
--   idx_latest_sessions_session_id, idx_expenses_reviewed_by,
--   idx_webhooks_events_gin_active (GIN), idx_webhooks_fanout_covering,
--   idx_webhook_deliveries_* (4), idx_queue_retry_intents_* (3)
--
-- ── Security & correctness fixes (2026-03-25 review) ──────────
--
-- Fix 1 — CONCURRENTLY removed from idx_gps_locations_session_recorded_at
--   CREATE INDEX CONCURRENTLY is not allowed inside transactions.
--   Supabase runs migrations inside transactions → use plain CREATE INDEX.
--
-- Fix 2 — USING (true) policies tightened to TO service_role
--   queue_retry_intents + webhook_deliveries now explicitly scoped to
--   service_role. Previously USING (true) with no role restriction gave
--   every authenticated user full unrestricted access.
--
-- Fix 3 — (SELECT auth.uid()) nesting removed throughout
--   auth.uid() is a stable inlined function; the SELECT wrapper adds
--   unnecessary subquery overhead and was a Supabase legacy workaround.
--
-- Fix 4 — Dual subquery pattern collapsed in admin_all RLS policies
--   Old pattern fetched organization_id and role via two separate subqueries
--   per row. New pattern does one lookup returning both fields as a boolean
--   expression, halving user table reads in RLS evaluation.
--
-- Fix 5 — GRANT EXECUTE added for authenticated role
--   Without this, PostgREST RPC calls silently fail with 404.
--   Applies to: get_org_latest_sessions, get_active_map_markers, and all
--   increment_* metrics functions called from the API layer.
--
-- Fix 6 — webhooks.secret plain-text storage documented
--   Column retained as-is to match live DB. Flagged for future migration
--   to Supabase Vault or hashed storage.
-- ══════════════════════════════════════════════════════════════